// Extract ticket fields from Linear webhook payload
const body = $input.first().json.body;
const data = body.data || {};
const updatedFrom = body.updatedFrom || {};

// Only process meaningful changes
const statusChanged = !!updatedFrom.stateId;
const titleChanged = !!updatedFrom.title;
const estimateChanged = updatedFrom.estimate !== undefined;
const parentChanged = updatedFrom.parentId !== undefined;

if (!statusChanged && !titleChanged && !estimateChanged && !parentChanged) {
  return [];  // Skip — no relevant field changed
}

// Map Linear status name to our canonical values
const statusMap = {
  'Backlog': 'Todo',
  'Todo': 'Todo',
  'In Progress': 'InProgress',
  'In Review': 'InProgress',
  'Done': 'Done',
  'Canceled': 'Done',
  'Blocked': 'Blocked'
};

const statusName = data.state?.name || 'Todo';

// Detect component from labels
const labels = (data.labels || []).map(l => l.name);
let component = '';
if (labels.some(l => l.includes('instance:backend'))) component = 'api';
else if (labels.some(l => l.includes('instance:frontend'))) component = 'ui';
else if (labels.some(l => l.includes('instance:mcp'))) component = 'gateway';
else if (labels.some(l => l.includes('instance:auth'))) component = 'auth';
else if (labels.some(l => l.includes('instance:qa'))) component = 'e2e';

// Detect cycle
const cycle = data.cycle?.name?.toLowerCase().includes('current') ? 'current' :
              data.cycle?.name?.toLowerCase().includes('next') ? 'next' : 'backlog';

// Build summary (first 200 chars of description)
const desc = data.description || '';
const summary = desc.substring(0, 200).replace(/\n/g, ' ').trim();

return [{
  json: {
    ticket_id: data.identifier || '',
    title: data.title || '',
    status: statusMap[statusName] || statusName,
    estimate: data.estimate || 0,
    priority: data.priority || 3,
    component: component,
    summary: summary,
    parent_id: data.parent?.identifier || '',
    cycle: cycle,
    updated_at: new Date().toISOString()
  }
}];
